class OrderController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {
  def getOrderById(id: Long): Action[AnyContent] = Action.async { implicit request =>
    val orderId = id.toLong
    val query = s"SELECT * FROM orders WHERE id = $orderId"
    db.withConnection { connection =>
      val resultSet = connection.prepareStatement(query).executeQuery()
      if (resultSet.next()) {
        val orderDetails = Json.obj(
